#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding hematology-assessment (16 tables)..."

cargo loco generate scaffold patient \
    full_name:text! \
    date_of_birth:text! \
    medical_record_number:text! \
    address:text! \
    telephone:text! \
    email:text! \
    gp_name:text! \
    gp_practice:text! \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:text! \
    --htmx

cargo loco generate scaffold assessment_patient_information \
    assessment:references \
    patient_name:text! \
    date_of_birth:text! \
    medical_record_number:text! \
    referring_physician:text! \
    clinical_indication:text! \
    specimen_date:text! \
    specimen_type:text! \
    --htmx

cargo loco generate scaffold assessment_blood_count_analysis \
    assessment:references \
    hemoglobin:double \
    hematocrit:double \
    red_blood_cell_count:double \
    white_blood_cell_count:double \
    platelet_count:double \
    mean_corpuscular_volume:double \
    mean_corpuscular_hemoglobin:double \
    red_cell_distribution_width:double \
    --htmx

cargo loco generate scaffold assessment_coagulation_studies \
    assessment:references \
    prothrombin_time:double \
    inr:double \
    activated_partial_thromboplastin_time:double \
    fibrinogen:double \
    d_dimer:double \
    bleeding_time:double \
    --htmx

cargo loco generate scaffold assessment_peripheral_blood_film \
    assessment:references \
    red_cell_morphology:text! \
    white_blood_cell_differential:text! \
    platelet_morphology:text! \
    abnormal_cell_morphology:text! \
    film_quality:int \
    film_comments:text! \
    --htmx

cargo loco generate scaffold assessment_iron_studies \
    assessment:references \
    serum_iron:double \
    total_iron_binding_capacity:double \
    transferrin_saturation:double \
    serum_ferritin:double \
    reticulocyte_count:double \
    --htmx

cargo loco generate scaffold assessment_hemoglobinopathy_screening \
    assessment:references \
    hemoglobin_electrophoresis:text! \
    sickle_cell_screen:text! \
    thalassemia_screen:text! \
    hplc_results:text! \
    genetic_testing_notes:text! \
    --htmx

cargo loco generate scaffold assessment_bone_marrow_assessment \
    assessment:references \
    aspirate_findings:text! \
    biopsy_findings:text! \
    cellularity:int \
    cytogenetics_results:text! \
    flow_cytometry_results:text! \
    bone_marrow_comments:text! \
    --htmx

cargo loco generate scaffold assessment_transfusion_history \
    assessment:references \
    previous_transfusions:text! \
    transfusion_reactions:text! \
    blood_group_type:text! \
    antibody_screen:text! \
    crossmatch_results:text! \
    --htmx

cargo loco generate scaffold assessment_treatment_medications \
    assessment:references \
    current_medications:text! \
    chemotherapy_regimen:text! \
    anticoagulant_therapy:text! \
    iron_therapy:text! \
    treatment_response:text! \
    adverse_effects:text! \
    --htmx

cargo loco generate scaffold assessment_clinical_review \
    assessment:references \
    clinical_summary:text! \
    diagnosis:text! \
    follow_up_plan:text! \
    urgency_level:int \
    reviewer_name:text! \
    review_date:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold hem_rule \
    category:text! \
    description:text! \
    concern_level:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    abnormality_level:text! \
    abnormality_score:double! \
    abnormality_level_override:text \
    override_reason:text! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    hem_rule:references \
    rule_category:text! \
    rule_description:text! \
    rule_concern_level:text! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:text! \
    category:text! \
    message:text! \
    priority:text! \
    --htmx

echo "Done."
